function validate(spec, args) {
  if (args.length !== spec.length) {
    return {
      error: `expected ${spec.length} args, got ${args.length}`
    };
  }

  const parsed = [];
  for (let i = 0; i < spec.length; i++) {
    const { name, type } = spec[i];
    const arg = args[i];

    if (type === 'string') {
      parsed.push(arg);
    } else if (type === 'int') {
      const num = parseInt(arg, 10);
      if (isNaN(num)) {
        return { error: `${name} must be int` };
      }
      parsed.push(num);
    } else if (type === 'positive-int') {
      const num = parseInt(arg, 10);
      if (isNaN(num) || num < 1) {
        return { error: `${name} must be positive-int` };
      }
      parsed.push(num);
    } else {
      throw new Error(`Unknown validation type: ${type}`);
    }
  }

  return { parsed };
}

module.exports = { validate };

